  const httpAdapter = getAiHttpProviderAdapter(safeProviderId);
  if (httpAdapter && typeof httpAdapter.listModels === 'function') {
    if (httpAdapter.requiresApiKey && !String(normalizedIntegration.apiKey || '').trim()) {
