function buildAbortableRunHandle(abortController) {
  const state = {
    exitCode: null,
    killed: false,
    pid: null,
    kill(signal = 'SIGTERM') {
      if (state.killed || state.exitCode !== null) return false;
      state.killed = true;
      state.exitCode = signal === 'SIGKILL' ? 137 : 143;
      try {
        abortController.abort();
