const assert=require('node:assert/strict');
const m=require('./server.js');
const db=m.db;

function getRouteHandler(method, path) {
  const layer = m.app._router.stack.find((entry) => entry.route && entry.route.path === path && entry.route.methods && entry.route.methods[method]);
  if (!layer) throw new Error(`route not found: ${method.toUpperCase()} ${path}`);
  const stack = layer.route.stack || [];
  if (stack.length === 0) throw new Error(`route stack empty: ${method.toUpperCase()} ${path}`);
  return stack[stack.length - 1].handle;
}

function createMockRes() {
  return {
    statusCode: 200,
    headers: {},
    body: null,
    status(code) {
      this.statusCode = Number(code);
      return this;
    },
    setHeader(name, value) {
      this.headers[String(name).toLowerCase()] = value;
    },
    getHeader(name) {
      return this.headers[String(name).toLowerCase()];
    },
    json(payload) {
      this.body = payload;
      return this;
    }
  };
}

async function invoke(handler, req) {
  const res = createMockRes();
  await handler(req, res, () => {});
  return { statusCode: res.statusCode, body: res.body };
}

